-- ----------------------------------------------------------------------------
-- vw_customers: Table: Customers
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_customers WITH (security_invoker = ON) AS
SELECT
  t.customer_id,
  calc_customers_name(t.customer_id) AS name,
  t.first_name,
  t.last_name,
  calc_customers_full_name(t.customer_id) AS full_name,
  t.notes,
  calc_customers_status_display_name(t.customer_id) AS status_display_name,
  calc_customers_status_is_blocking(t.customer_id) AS status_is_blocking,
  calc_customers_is_stopped(t.customer_id) AS is_stopped,
  calc_customers_status_description(t.customer_id) AS status_description,
  t.status,
  t.owner_email                                                                 -- Email address of the user who owns this customer record. Used by Row-Level Security to scope visibility to the JWT email of the requester.
FROM customers t;

-- ----------------------------------------------------------------------------
-- vw_statuses: Table: Statuses
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_statuses WITH (security_invoker = ON) AS
SELECT
  t.statuse_id,
  calc_statuses_name(t.statuse_id) AS name,
  t.display_name,
  t.description,
  t.is_blocking,
  t.customers,
  t.owner_email                                                                 -- Email address of the user who owns this status. Used by Row-Level Security to scope visibility.
FROM statuses t;

-- ----------------------------------------------------------------------------
-- vw_app_users: Table: AppUsers
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_app_users WITH (security_invoker = ON) AS
SELECT
  t.app_user_id,
  calc_app_users_name(t.app_user_id) AS name,
  t.email_address,                                                              -- Primary identity — matches the JWT email of the signed-in user.
  t.role                                                                        -- admin = full access; customer = sees only owned customers (RLS DAG).
FROM app_users t;

